import { getContext, getSettings } from '../core/context';
import { safeText, toErrorMessage, withTimeout } from '../core/utils';
import type { GenerateOptions } from '../types';

let profileMutex: Promise<unknown> = Promise.resolve();

function slashResultText(result: any): string {
  if (typeof result === 'string') return result.trim();
  for (const key of ['pipe', 'output', 'result', 'text', 'value']) {
    if (typeof result?.[key] === 'string') return result[key].trim();
  }
  return '';
}

function cleanProfileName(value: unknown): string {
  return safeText(value, 160).replace(/["|\r\n]/g, '').trim();
}

async function generateCurrent(options: GenerateOptions): Promise<string> {
  const context = getContext();
  if (typeof context.generateRaw !== 'function') throw new Error('当前SillyTavern未提供generateRaw');
  const settings = getSettings();
  const result = await withTimeout(
    Promise.resolve(context.generateRaw({ systemPrompt: options.systemPrompt, prompt: options.prompt })),
    Math.max(10000, Number(settings.requestTimeoutMs) || 90000),
    `${options.task}模型调用`,
  );
  return safeText(result, 200000);
}

async function generateWithProfile(options: GenerateOptions, profileName: string): Promise<string> {
  const profile = cleanProfileName(profileName);
  if (!profile) throw new Error('连接配置名称为空');

  const run = async (): Promise<string> => {
    let slashModule: any;
    try {
      const moduleUrl = '/scripts/slash-commands.js';
    slashModule = await import(/* @vite-ignore */ moduleUrl);
    } catch (error) {
      throw new Error(`无法加载连接配置切换器：${toErrorMessage(error)}`);
    }
    const execute = slashModule?.executeSlashCommands;
    if (typeof execute !== 'function') throw new Error('当前SillyTavern不支持连接配置命令');

    const original = slashResultText(await execute('/profile'));
    await execute(`/profile "${profile}"`);
    try {
      return await generateCurrent(options);
    } finally {
      if (original && original !== profile) {
        try {
          await execute(`/profile "${cleanProfileName(original)}"`);
        } catch (error) {
          console.warn('[MirrorAbyss] failed to restore profile', error);
        }
      }
    }
  };

  const chained = profileMutex.then(run, run);
  profileMutex = chained.catch(() => undefined);
  return chained;
}

export async function generateTask(options: GenerateOptions): Promise<string> {
  const connection = getSettings().connections[options.task];
  if (connection?.mode === 'profile') return generateWithProfile(options, connection.profile);
  return generateCurrent(options);
}

export async function testConnection(task: GenerateOptions['task']): Promise<string> {
  const raw = await generateTask({
    task,
    systemPrompt: '你是连接测试器。',
    prompt: '只回复 MA_OK',
  });
  if (!/MA_OK/i.test(raw)) throw new Error(`连接可用，但返回内容异常：${raw.slice(0, 120)}`);
  return 'MA_OK';
}
