import { getChat, getSettings } from '../core/context';
import { parseJsonObject, toErrorMessage } from '../core/utils';
import { markStage } from '../domain/artifact';
import { normalizeSummary } from '../domain/summary';
import { generateTask } from '../llm/generator';
import { largeSummaryPrompt, largeSummarySystemPrompt, smallSummaryPrompt, smallSummarySystemPrompt } from '../prompts/summary';
import { getChatState, putArtifact, putChatState } from '../storage/repository';
import type { MessageArtifact, StateSnapshot, SummaryArtifact } from '../types';

function successfulArtifacts(): MessageArtifact[] {
  return getChat()
    .filter((message) => !message?.is_user)
    .map((message) => message?.extra?.mirrorAbyssV11 as MessageArtifact | undefined)
    .filter((artifact): artifact is MessageArtifact => Boolean(artifact?.snapshot && artifact.stages.state.status === 'success'));
}

function transcriptFor(artifacts: MessageArtifact[]): string {
  return artifacts.map((artifact) => `【回合 ${artifact.messageIndex + 1}】\n玩家：${artifact.playerText || '（空）'}\n正文：${artifact.assistantText}`).join('\n\n');
}

function allConsumedKeys(summaries: SummaryArtifact[]): Set<string> {
  return new Set(summaries.flatMap((item) => item.sourceKeys));
}

export async function generateSmallSummary(artifact: MessageArtifact, force = false): Promise<SummaryArtifact | null> {
  const settings = getSettings();
  const chatState = await getChatState(artifact.chatKey);
  const consumed = allConsumedKeys(chatState.smallSummaries);
  const pending = successfulArtifacts().filter((item) => !consumed.has(item.messageKey));
  const threshold = Math.max(1, Number(settings.smallSummaryTurns) || 15);
  if (!force && pending.length < threshold) return null;
  if (!pending.length) return null;
  const selected = force ? pending : pending.slice(0, threshold);
  const latestSnapshot = selected.at(-1)?.snapshot as StateSnapshot;
  const raw = await generateTask({
    task: 'smallSummary',
    systemPrompt: smallSummarySystemPrompt(),
    prompt: smallSummaryPrompt(transcriptFor(selected), latestSnapshot),
  });
  const summary = normalizeSummary(parseJsonObject(raw), 'small', selected.map((item) => item.messageKey));
  chatState.smallSummaries.push(summary);
  await putChatState(chatState);
  return summary;
}

export async function generateLargeSummary(artifact: MessageArtifact, force = false): Promise<SummaryArtifact | null> {
  const settings = getSettings();
  const chatState = await getChatState(artifact.chatKey);
  const consumed = allConsumedKeys(chatState.largeSummaries);
  const pending = chatState.smallSummaries.filter((item) => !consumed.has(item.id));
  const threshold = Math.max(1, Number(settings.largeSummaryCount) || 6);
  if (!force && pending.length < threshold) return null;
  if (!pending.length) return null;
  const selected = force ? pending : pending.slice(0, threshold);
  const snapshot = artifact.snapshot;
  if (!snapshot) throw new Error('没有可用于大总结的状态表');
  const raw = await generateTask({
    task: 'largeSummary',
    systemPrompt: largeSummarySystemPrompt(),
    prompt: largeSummaryPrompt(selected, snapshot),
  });
  const summary = normalizeSummary(parseJsonObject(raw), 'large', selected.map((item) => item.id));
  chatState.largeSummaries.push(summary);
  await putChatState(chatState);
  return summary;
}

export async function maybeRunSummaries(artifact: MessageArtifact, forceSmall = false, forceLarge = false): Promise<void> {
  const settings = getSettings();
  markStage(artifact, 'summary', 'running');
  await putArtifact(artifact);
  try {
    if (settings.autoSmallSummary || forceSmall) await generateSmallSummary(artifact, forceSmall);
    if (settings.autoLargeSummary || forceLarge) await generateLargeSummary(artifact, forceLarge);
    markStage(artifact, 'summary', 'success');
    await putArtifact(artifact);
  } catch (error) {
    markStage(artifact, 'summary', 'failed', toErrorMessage(error));
    await putArtifact(artifact);
    throw error;
  }
}
