let selectedMessageIndex: number | null = null;
let rendering = false;
let queueUnsubscribe: (() => void) | null = null;

function root(): HTMLElement {
  let element = document.querySelector<HTMLElement>('#ma11-workspace');
  if (element) return element;
  document.body.insertAdjacentHTML('beforeend', `
    <div id="ma11-workspace" class="ma11-workspace" hidden>
      <div class="ma11-shell" role="dialog" aria-modal="true" aria-label="镜渊控制中心">
        <header class="ma11-header">
          <div>
            <div class="ma11-brand">镜渊 <span>${VERSION}</span></div>
            <div class="ma11-subtitle">结构化状态、分层总结与世界书发布</div>
          </div>
          <button class="ma11-icon-button" data-ma11-action="close" aria-label="关闭">×</button>
        </header>
        <nav class="ma11-tabs" aria-label="镜渊功能">
          ${[
            ['overview', '总览'], ['tables', '状态表'], ['summaries', '总结'], ['audit', '规则审核'],
            ['sync', '世界书'], ['settings', '模型与设置'], ['diagnostics', '诊断'],
          ].map(([key, label]) => `<button data-ma11-tab="${key}">${label}</button>`).join('')}
        </nav>
        <main id="ma11-workspace-content" class="ma11-content"></main>
      </div>
      <div class="ma11-editor-backdrop" hidden>
        <form class="ma11-editor" id="ma11-row-editor">
          <header><b>编辑状态行</b><button type="button" data-ma11-action="close-editor">×</button></header>
          <input type="hidden" name="tableKey" />
          <input type="hidden" name="rowId" />
          <label>对象<input name="title" required maxlength="240" /></label>
          <label>当前事实<textarea name="content" rows="6" maxlength="12000"></textarea></label>
          <label>状态<input name="status" maxlength="120" /></label>
          <label>关键词（逗号分隔）<input name="keywords" maxlength="800" /></label>
          <footer><button type="button" data-ma11-action="close-editor">取消</button><button type="submit">保存</button></footer>
        </form>
      </div>
    </div>`);
  element = document.querySelector<HTMLElement>('#ma11-workspace')!;
  bindWorkspace(element);
  queueUnsubscribe ||= taskQueue.subscribe(() => void renderWorkspace());
  return element;
}

function currentArtifact(): { index: number; artifact: MessageArtifact } | null {
  if (selectedMessageIndex !== null) {
    const artifact = getArtifactAt(selectedMessageIndex);
    if (artifact) return { index: selectedMessageIndex, artifact };
  }
  return latestArtifact();
}

function statusText(value: string): string {
  const map: Record<string, string> = {
    idle: '等待', queued: '排队', running: '处理中', success: '成功', failed: '失败', skipped: '跳过', blocked: '阻断',
  };
  return map[value] || value;
}

function statusClass(value: string): string {
  if (value === 'success' || value === 'skipped') return 'success';
  if (value === 'failed' || value === 'blocked') return 'danger';
  if (value === 'running' || value === 'queued') return 'working';
  return 'neutral';
}

function stageCards(artifact?: MessageArtifact): string {
  const stages = artifact?.stages;
  const rows = [
    ['audit', '规则审核'], ['state', '状态提取'], ['summary', '分层总结'], ['sync', '世界书同步'],
  ] as const;
  return `<div class="ma11-stage-grid">${rows.map(([key, label]) => {
    const stage = stages?.[key] ?? { status: 'idle', attempts: 0 };
    return `<article class="ma11-stage-card ${statusClass(stage.status)}">
      <div><b>${label}</b><span>${statusText(stage.status)}</span></div>
      <small>尝试 ${stage.attempts || 0} 次</small>
      ${stage.error ? `<p>${escapeHtml(stage.error)}</p>` : ''}
    </article>`;
  }).join('')}</div>`;
}

function overviewHtml(artifactInfo: ReturnType<typeof currentArtifact>): string {
  const artifact = artifactInfo?.artifact;
  const rows = snapshotRowCount(artifact?.snapshot);
  const jobs = taskQueue.list().slice(0, 5);
  return `
    <section class="ma11-hero">
      <div>
        <h2>${artifact ? `第 ${artifact.messageIndex + 1} 条正文` : '当前聊天尚无镜渊记录'}</h2>
        <p>${artifact ? `状态表 ${rows} 条 · 更新时间 ${escapeHtml(new Date(artifact.updatedAt).toLocaleString())}` : '生成一条AI正文，或手动整理最新正文。'}</p>
      </div>
      <div class="ma11-actions">
        <button data-ma11-action="process-latest">整理最新正文</button>
        <button data-ma11-action="open-tables" ${artifact?.snapshot ? '' : 'disabled'}>查看状态表</button>
      </div>
    </section>
    ${stageCards(artifact)}
    <section class="ma11-card">
      <header><b>任务队列</b><span>${jobs.length ? `${jobs.length} 条最近任务` : '空闲'}</span></header>
      <div class="ma11-task-list">
        ${jobs.length ? jobs.map((task) => `<div><span>${escapeHtml(task.label)}</span><em class="${task.state}">${escapeHtml(task.state)}</em></div>`).join('') : '<p class="ma11-empty">没有运行中的任务。</p>'}
      </div>
    </section>
    <section class="ma11-card ma11-note">
      <b>本版架构原则</b>
      <p>每条AI正文只创建一个唯一任务；审核、表格、总结、同步分阶段保存。单一阶段失败时只重试该阶段，不重新调用整条管线。</p>
    </section>`;
}

function tableHtml(artifactInfo: ReturnType<typeof currentArtifact>): string {
  const settings = getSettings();
  const artifact = artifactInfo?.artifact;
  const active = settings.ui.activeTable;
  const rows = artifact?.snapshot?.[active] ?? [];
  return `
    <section class="ma11-toolbar">
      <div class="ma11-table-tabs">${TABLE_KEYS.map((key) => `<button class="${key === active ? 'active' : ''}" data-ma11-table="${key}">${TABLE_LABELS[key]} <span>${artifact?.snapshot?.[key]?.length ?? 0}</span></button>`).join('')}</div>
      <div class="ma11-actions"><button data-ma11-action="add-row" ${artifact?.snapshot ? '' : 'disabled'}>＋ 添加</button><button data-ma11-action="retry-state" ${artifactInfo ? '' : 'disabled'}>重新整理</button></div>
    </section>
    <section class="ma11-table-wrap">
      ${artifact?.snapshot ? `<table class="ma11-table">
        <thead><tr><th>序号</th><th>对象</th><th>当前事实</th><th>状态</th><th>关键词</th><th>来源</th><th>操作</th></tr></thead>
        <tbody>${rows.length ? rows.map((row, index) => `<tr>
          <td>${index + 1}</td>
          <td><b>${escapeHtml(row.title)}</b></td>
          <td class="ma11-cell-content">${escapeHtml(row.content)}</td>
          <td>${escapeHtml(row.status)}</td>
          <td>${row.keywords.map((word) => `<span class="ma11-keyword">${escapeHtml(word)}</span>`).join('')}</td>
          <td><span class="ma11-source ${row.source}">${row.source === 'manual' ? '手动' : '自动'}</span></td>
          <td><button data-ma11-edit-row="${escapeHtml(row.id)}">编辑</button><button class="danger" data-ma11-delete-row="${escapeHtml(row.id)}">删除</button></td>
        </tr>`).join('') : `<tr><td colspan="7" class="ma11-empty">该分类暂无记录。</td></tr>`}</tbody>
      </table>` : '<div class="ma11-empty-panel">尚无状态表。点击“整理最新正文”。</div>'}
    </section>`;
}

