async function diagnosticsHtml(): Promise<string> {
  const checks = await runDiagnostics();
  const info = currentArtifact();
  const logs = info ? await getTaskLog(info.artifact.chatKey) : [];
  return `
    <section class="ma11-toolbar"><div><h2>运行诊断</h2><p>入口、模型、存储与同步分别检查。</p></div><div class="ma11-actions"><button data-ma11-action="refresh-diagnostics">刷新</button><button data-ma11-action="copy-diagnostics">复制诊断</button></div></section>
    <section class="ma11-check-grid">${checks.map((check) => `<article class="ma11-check ${check.status}"><span></span><div><b>${escapeHtml(check.label)}</b><p>${escapeHtml(check.detail)}</p></div></article>`).join('')}</section>
    <section class="ma11-card"><header><b>最近任务日志</b><span>${logs.length}</span></header><div class="ma11-log-list">${logs.length ? logs.slice(0, 30).map((log) => `<div><time>${escapeHtml(new Date(log.createdAt).toLocaleString())}</time><span>${escapeHtml(log.label)}</span><em class="${log.state}">${escapeHtml(log.state)}</em>${log.error ? `<small>${escapeHtml(log.error)}</small>` : ''}</div>`).join('') : '<p class="ma11-empty">暂无日志。</p>'}</div></section>`;
}

async function renderWorkspace(): Promise<void> {
  const workspace = document.querySelector<HTMLElement>('#ma11-workspace');
  if (!workspace || workspace.hidden || rendering) return;
  rendering = true;
  try {
    const settings = getSettings();
    const info = currentArtifact();
    workspace.querySelectorAll<HTMLElement>('[data-ma11-tab]').forEach((button) => button.classList.toggle('active', button.dataset.ma11Tab === settings.ui.activeTab));
    const content = workspace.querySelector<HTMLElement>('#ma11-workspace-content')!;
    if (settings.ui.activeTab === 'overview') content.innerHTML = overviewHtml(info);
    if (settings.ui.activeTab === 'tables') content.innerHTML = tableHtml(info);
    if (settings.ui.activeTab === 'summaries') content.innerHTML = await summariesHtml();
    if (settings.ui.activeTab === 'audit') content.innerHTML = auditHtml();
    if (settings.ui.activeTab === 'sync') content.innerHTML = await syncHtml();
    if (settings.ui.activeTab === 'settings') content.innerHTML = settingsHtml();
    if (settings.ui.activeTab === 'diagnostics') content.innerHTML = await diagnosticsHtml();
  } finally {
    rendering = false;
  }
}

function setTab(tab: any): void {
  const settings = getSettings();
  settings.ui.activeTab = tab;
  saveSettings();
  void renderWorkspace();
}

function openRowEditor(tableKey: TableKey, row?: StateRow): void {
  const workspace = root();
  const backdrop = workspace.querySelector<HTMLElement>('.ma11-editor-backdrop')!;
  const form = workspace.querySelector<HTMLFormElement>('#ma11-row-editor')!;
  (form.elements.namedItem('tableKey') as HTMLInputElement).value = tableKey;
  (form.elements.namedItem('rowId') as HTMLInputElement).value = row?.id || '';
  (form.elements.namedItem('title') as HTMLInputElement).value = row?.title || '';
  (form.elements.namedItem('content') as HTMLTextAreaElement).value = row?.content || '';
  (form.elements.namedItem('status') as HTMLInputElement).value = row?.status || 'active';
  (form.elements.namedItem('keywords') as HTMLInputElement).value = row?.keywords.join(', ') || '';
  backdrop.hidden = false;
  (form.elements.namedItem('title') as HTMLInputElement).focus();
}

function closeEditor(): void {
  const workspace = document.querySelector<HTMLElement>('#ma11-workspace');
  const backdrop = workspace?.querySelector<HTMLElement>('.ma11-editor-backdrop');
  if (backdrop) backdrop.hidden = true;
}

async function saveRow(form: HTMLFormElement): Promise<void> {
  const info = currentArtifact();
  if (!info?.artifact.snapshot) throw new Error('当前没有可编辑的状态表');
  const tableKey = (form.elements.namedItem('tableKey') as HTMLInputElement).value as TableKey;
  const rowId = (form.elements.namedItem('rowId') as HTMLInputElement).value;
  const title = (form.elements.namedItem('title') as HTMLInputElement).value.trim();
  const content = (form.elements.namedItem('content') as HTMLTextAreaElement).value.trim();
  const status = (form.elements.namedItem('status') as HTMLInputElement).value.trim();
  const keywords = (form.elements.namedItem('keywords') as HTMLInputElement).value.split(/[,，]/).map((item) => item.trim()).filter(Boolean);
  info.artifact.snapshot = upsertManualRow(info.artifact.snapshot, tableKey, { id: rowId || undefined, title, content, status, keywords });
  const message = getMessage(info.index);
  if (message) attachArtifactToMessage(message, info.artifact);
  await putArtifact(info.artifact);
  await persistChat();
  closeEditor();
  await renderWorkspace();
}

async function deleteRowAction(rowId: string): Promise<void> {
  const info = currentArtifact();
  if (!info?.artifact.snapshot) return;
  const tableKey = getSettings().ui.activeTable;
  if (!confirm('确定删除这条状态吗？')) return;
  info.artifact.snapshot = deleteRow(info.artifact.snapshot, tableKey, rowId);
  const message = getMessage(info.index);
  if (message) attachArtifactToMessage(message, info.artifact);
  await putArtifact(info.artifact);
  await persistChat();
  await renderWorkspace();
}

function updateSetting(target: HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement): void {
  const key = target.dataset.ma11Setting;
  if (!key) return;
  const settings: any = getSettings();
  const value = target instanceof HTMLInputElement && target.type === 'checkbox'
    ? target.checked
    : target instanceof HTMLInputElement && target.type === 'number'
      ? Number(target.value)
      : target.value;
  settings[key] = value;
  saveSettings();
}

function updateConnection(target: HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement): void {
  const modeTask = target.dataset.ma11ConnectionMode as TaskKind | undefined;
  const profileTask = target.dataset.ma11ConnectionProfile as TaskKind | undefined;
  const settings = getSettings();
  let shouldRender = false;
  if (modeTask) {
    settings.connections[modeTask].mode = target.value as any;
    shouldRender = true;
  }
  if (profileTask) settings.connections[profileTask].profile = safeText(target.value, 160).trim();
  saveSettings();
  if (shouldRender) void renderWorkspace();
}

function bindWorkspace(workspace: HTMLElement): void {
  workspace.addEventListener('click', async (event) => {
    const target = event.target as HTMLElement;
    const tab = target.closest<HTMLElement>('[data-ma11-tab]')?.dataset.ma11Tab;
    if (tab) return setTab(tab);
    const action = target.closest<HTMLElement>('[data-ma11-action]')?.dataset.ma11Action;
    try {
      if (action === 'close') workspace.hidden = true;
      if (action === 'open-tables') setTab('tables');
      if (action === 'process-latest') {
        const index = latestAssistantIndex();
        if (index < 0) throw new Error('没有可整理的AI正文');
        selectedMessageIndex = index;
        await processMessage(index, true);
        await renderWorkspace();
      }
      if (action === 'retry-state') {
        const info = currentArtifact();
        if (info) await retryStage(info.index, 'state');
        await renderWorkspace();
      }
      if (action === 'force-small' || action === 'force-large') {
        const info = currentArtifact();
        if (!info) throw new Error('尚无可总结的状态');
        await forceSummary(info.index, action === 'force-small' ? 'small' : 'large');
        await renderWorkspace();
      }
      if (action === 'retry-sync') {
        const info = currentArtifact();
        if (!info) throw new Error('尚无可同步的状态');
        await retryStage(info.index, 'sync');
        await renderWorkspace();
      }
      if (action === 'add-row') openRowEditor(getSettings().ui.activeTable);
      if (action === 'close-editor') closeEditor();
      if (action === 'refresh-diagnostics') await renderWorkspace();
      if (action === 'copy-diagnostics') {
        const report = await diagnosticReport();
        await navigator.clipboard.writeText(JSON.stringify(report, null, 2));
        toast('success', '诊断信息已复制');
      }
      const table = target.closest<HTMLElement>('[data-ma11-table]')?.dataset.ma11Table as TableKey | undefined;
      if (table) {
        getSettings().ui.activeTable = table;
        saveSettings();
        await renderWorkspace();
      }
      const editId = target.closest<HTMLElement>('[data-ma11-edit-row]')?.dataset.ma11EditRow;
      if (editId) {
        const info = currentArtifact();
        const key = getSettings().ui.activeTable;
        const row = info?.artifact.snapshot?.[key].find((item) => item.id === editId);
        if (row) openRowEditor(key, row);
      }
      const deleteId = target.closest<HTMLElement>('[data-ma11-delete-row]')?.dataset.ma11DeleteRow;
      if (deleteId) await deleteRowAction(deleteId);
      const testTask = target.closest<HTMLElement>('[data-ma11-test]')?.dataset.ma11Test as TaskKind | undefined;
      if (testTask) {
        await testConnection(testTask);
        toast('success', `${testTask}连接正常`);
      }
    } catch (error) {
      toast('error', toErrorMessage(error));
    }
  });

  workspace.addEventListener('change', (event) => {
    const target = event.target as HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement;
    if (target.dataset.ma11Setting) updateSetting(target);
    if (target.dataset.ma11ConnectionMode || target.dataset.ma11ConnectionProfile) updateConnection(target);
  });
  workspace.addEventListener('input', (event) => {
    const target = event.target as HTMLInputElement | HTMLTextAreaElement;
    if (target.dataset.ma11Setting === 'auditPrompt' || target.dataset.ma11Setting === 'lorebookName') updateSetting(target);
    if (target.dataset.ma11ConnectionProfile) updateConnection(target);
  });
  workspace.querySelector<HTMLFormElement>('#ma11-row-editor')?.addEventListener('submit', (event) => {
    event.preventDefault();
    void saveRow(event.currentTarget as HTMLFormElement).catch((error) => toast('error', toErrorMessage(error)));
  });
}

export function openWorkspace(tab?: any, messageIndex?: number): void {
  const workspace = root();
  if (Number.isInteger(messageIndex)) selectedMessageIndex = Number(messageIndex);
  if (tab) getSettings().ui.activeTab = tab;
  workspace.hidden = false;
  void renderWorkspace();
}

export function closeWorkspace(): void {
  const workspace = document.querySelector<HTMLElement>('#ma11-workspace');
  if (workspace) workspace.hidden = true;
}

export function refreshWorkspace(): void {
  void renderWorkspace();
}
