import { STORAGE_ARTIFACT_PREFIX, STORAGE_CHAT_PREFIX, STORAGE_DB_NAME, STORAGE_LOG_PREFIX } from '../constants';
import type { ChatState, MessageArtifact, QueueTask } from '../types';
import { nowIso } from '../core/utils';

interface StorageAdapter {
  getItem<T>(key: string): Promise<T | null>;
  setItem<T>(key: string, value: T): Promise<T>;
  removeItem(key: string): Promise<void>;
  keys(): Promise<string[]>;
}

let adapter: StorageAdapter | null = null;

function getAdapter(): StorageAdapter {
  if (adapter) return adapter;
  const localforage = globalThis.SillyTavern?.libs?.localforage;
  if (localforage?.createInstance) {
    adapter = localforage.createInstance({ name: STORAGE_DB_NAME, storeName: 'mirror_abyss' }) as StorageAdapter;
    return adapter;
  }
  adapter = {
    async getItem<T>(key: string) {
      const raw = localStorage.getItem(`${STORAGE_DB_NAME}:${key}`);
      return raw ? (JSON.parse(raw) as T) : null;
    },
    async setItem<T>(key: string, value: T) {
      localStorage.setItem(`${STORAGE_DB_NAME}:${key}`, JSON.stringify(value));
      return value;
    },
    async removeItem(key: string) {
      localStorage.removeItem(`${STORAGE_DB_NAME}:${key}`);
    },
    async keys() {
      return Object.keys(localStorage)
        .filter((key) => key.startsWith(`${STORAGE_DB_NAME}:`))
        .map((key) => key.slice(STORAGE_DB_NAME.length + 1));
    },
  };
  return adapter;
}

export async function getChatState(chatKey: string): Promise<ChatState> {
  const key = `${STORAGE_CHAT_PREFIX}${chatKey}`;
  const existing = await getAdapter().getItem<ChatState>(key);
  return existing ?? {
    schemaVersion: 1,
    chatKey,
    processedMessageKeys: [],
    smallSummaries: [],
    largeSummaries: [],
    lastSyncStatus: 'idle',
    updatedAt: nowIso(),
  };
}

export async function putChatState(state: ChatState): Promise<void> {
  state.updatedAt = nowIso();
  await getAdapter().setItem(`${STORAGE_CHAT_PREFIX}${state.chatKey}`, state);
}

export async function getArtifact(chatKey: string, messageKey: string): Promise<MessageArtifact | null> {
  return getAdapter().getItem<MessageArtifact>(`${STORAGE_ARTIFACT_PREFIX}${chatKey}:${messageKey}`);
}

export async function putArtifact(artifact: MessageArtifact): Promise<void> {
  artifact.updatedAt = nowIso();
  await getAdapter().setItem(`${STORAGE_ARTIFACT_PREFIX}${artifact.chatKey}:${artifact.messageKey}`, artifact);
}

export async function removeArtifact(chatKey: string, messageKey: string): Promise<void> {
  await getAdapter().removeItem(`${STORAGE_ARTIFACT_PREFIX}${chatKey}:${messageKey}`);
}

export async function appendTaskLog(chatKey: string, task: QueueTask): Promise<void> {
  const key = `${STORAGE_LOG_PREFIX}${chatKey}`;
  const logs = (await getAdapter().getItem<QueueTask[]>(key)) ?? [];
  logs.unshift(task);
  await getAdapter().setItem(key, logs.slice(0, 200));
}

export async function getTaskLog(chatKey: string): Promise<QueueTask[]> {
  return (await getAdapter().getItem<QueueTask[]>(`${STORAGE_LOG_PREFIX}${chatKey}`)) ?? [];
}

export async function clearAllStorage(): Promise<void> {
  const storage = getAdapter();
  const keys = await storage.keys();
  await Promise.all(keys.filter((key) => key.startsWith('ma11:')).map((key) => storage.removeItem(key)));
}
