import type { QueueTask } from '../types';
import { appendTaskLog } from '../storage/repository';
import { currentChatKey } from '../core/context';
import { makeId, nowIso, toErrorMessage } from '../core/utils';

export class TaskQueue {
  private tail: Promise<unknown> = Promise.resolve();
  private inFlight = new Map<string, Promise<unknown>>();
  private tasks = new Map<string, QueueTask>();
  private listeners = new Set<() => void>();

  subscribe(listener: () => void): () => void {
    this.listeners.add(listener);
    return () => this.listeners.delete(listener);
  }

  private notify(): void {
    for (const listener of this.listeners) {
      try {
        listener();
      } catch (error) {
        console.warn('[MirrorAbyss] task listener failed', error);
      }
    }
  }

  list(): QueueTask[] {
    return [...this.tasks.values()].sort((a, b) => b.createdAt.localeCompare(a.createdAt));
  }

  has(key: string): boolean {
    return this.inFlight.has(key);
  }

  run<T>(key: string, label: string, kind: QueueTask['kind'], work: () => Promise<T>): Promise<T> {
    const existing = this.inFlight.get(key);
    if (existing) return existing as Promise<T>;

    const task: QueueTask = {
      id: makeId('task'),
      key,
      label,
      kind,
      state: 'queued',
      createdAt: nowIso(),
    };
    this.tasks.set(task.id, task);
    this.notify();

    const execute = async (): Promise<T> => {
      task.state = 'running';
      task.startedAt = nowIso();
      this.notify();
      try {
        const result = await work();
        task.state = 'success';
        return result;
      } catch (error) {
        task.state = 'failed';
        task.error = toErrorMessage(error);
        throw error;
      } finally {
        task.finishedAt = nowIso();
        this.inFlight.delete(key);
        try {
          await appendTaskLog(currentChatKey(), { ...task });
        } catch (error) {
          console.warn('[MirrorAbyss] task log save failed', error);
        }
        this.notify();
      }
    };

    const promise = this.tail.then(execute, execute);
    this.tail = promise.catch(() => undefined);
    this.inFlight.set(key, promise);
    return promise;
  }
}

export const taskQueue = new TaskQueue();
