import type { StateSnapshot, SummaryArtifact } from '../types';

export function smallSummarySystemPrompt(): string {
  return '你是镜渊阶段快照结算器。只输出合法JSON对象，字段为 title、summary、keywords。不要续写故事，不把未确认事项写成事实。';
}

export function smallSummaryPrompt(transcript: string, snapshot: StateSnapshot): string {
  return `将以下回合压缩成“当前世界快照式小总结”。不是流水账。重点保留：确定结果、不可逆变化、当前人物/关系/物品/区域状态、仍在进行的流程、未决与冲突。已经被最终结果替代的中间动作不展开。

【回合】
${transcript}

【当前状态表】
${JSON.stringify(snapshot, null, 2)}

只输出：{"title":"...","summary":"...","keywords":["..."]}`;
}

export function largeSummarySystemPrompt(): string {
  return '你是镜渊长期快照结算器。只输出合法JSON对象，字段为 title、summary、keywords。';
}

export function largeSummaryPrompt(summaries: SummaryArtifact[], snapshot: StateSnapshot): string {
  const source = summaries.map((item) => `【${item.title}】\n${item.summary}`).join('\n\n');
  return `将下列小总结再次压缩成长期快照。保留长期仍成立的人物、关系、区域、物品、事件结果和未决事项；不要复述阶段流水账，不要强行闭合开放事件。

${source}

【当前状态表】
${JSON.stringify(snapshot, null, 2)}

只输出：{"title":"...","summary":"...","keywords":["..."]}`;
}
