import { TABLE_KEYS } from '../constants';
import { getChat, getSettings } from '../core/context';
import { parseJsonObject, toErrorMessage } from '../core/utils';
import { markStage } from '../domain/artifact';
import { emptySnapshot, normalizeSnapshot } from '../domain/snapshot';
import { generateTask } from '../llm/generator';
import { stateSystemPrompt, stateUserPrompt } from '../prompts/state';
import { putArtifact } from '../storage/repository';
import type { MessageArtifact, StateSnapshot } from '../types';

export function previousSnapshot(beforeIndex: number): StateSnapshot {
  const chat = getChat();
  for (let i = beforeIndex - 1; i >= 0; i -= 1) {
    if (chat[i]?.is_user) continue;
    const snapshot = chat[i]?.extra?.mirrorAbyssV11?.snapshot as StateSnapshot | undefined;
    if (snapshot) return normalizeSnapshot(snapshot, snapshot);
    const legacy = chat[i]?.extra?.mirrorAbyss?.tableSnapshot as StateSnapshot | undefined;
    if (legacy) return normalizeSnapshot(legacy, legacy);
  }
  return emptySnapshot();
}

function restoreManualRows(previous: StateSnapshot, next: StateSnapshot): StateSnapshot {
  for (const key of TABLE_KEYS) {
    const existing = new Set(next[key].map((row) => row.id));
    for (const row of previous[key]) {
      if (row.source === 'manual' && !existing.has(row.id)) next[key].push({ ...row });
    }
  }
  return next;
}

export async function runStateExtraction(artifact: MessageArtifact, force = false): Promise<StateSnapshot> {
  if (!force && artifact.stages.state.status === 'success' && artifact.snapshot) return artifact.snapshot;
  const settings = getSettings();
  const previous = previousSnapshot(artifact.messageIndex);
  markStage(artifact, 'state', 'running');
  await putArtifact(artifact);

  try {
    let raw = await generateTask({
      task: 'state',
      systemPrompt: stateSystemPrompt(),
      prompt: stateUserPrompt(previous, artifact.playerText, artifact.assistantText),
    });
    let parsed: Record<string, any>;
    try {
      parsed = parseJsonObject(raw);
    } catch (firstError) {
      if (!settings.repairInvalidJsonOnce) throw firstError;
      raw = await generateTask({
        task: 'state',
        systemPrompt: stateSystemPrompt(),
        prompt: stateUserPrompt(previous, artifact.playerText, artifact.assistantText, true),
      });
      parsed = parseJsonObject(raw);
    }
    const normalized = restoreManualRows(previous, normalizeSnapshot(parsed, previous));
    artifact.snapshot = normalized;
    markStage(artifact, 'state', 'success');
    await putArtifact(artifact);
    return normalized;
  } catch (error) {
    markStage(artifact, 'state', 'failed', toErrorMessage(error));
    await putArtifact(artifact);
    throw error;
  }
}
