import { VERSION } from '../constants';
import { currentChatKey, getSettings, tryGetContext } from '../core/context';
import { getChatState, getTaskLog } from '../storage/repository';
import type { DiagnosticCheck } from '../types';

export async function runDiagnostics(): Promise<DiagnosticCheck[]> {
  const checks: DiagnosticCheck[] = [];
  const context = tryGetContext();
  checks.push({
    id: 'context',
    label: 'SillyTavern上下文',
    status: context ? 'ok' : 'error',
    detail: context ? '已连接' : '不可用',
  });
  checks.push({
    id: 'generateRaw',
    label: '后台模型调用',
    status: typeof context?.generateRaw === 'function' ? 'ok' : 'error',
    detail: typeof context?.generateRaw === 'function' ? 'generateRaw可用' : '当前版本未提供generateRaw',
  });
  checks.push({
    id: 'settingsPanel',
    label: '扩展设置入口',
    status: document.querySelector('#ma11-settings-root') ? 'ok' : 'warn',
    detail: document.querySelector('#ma11-settings-root') ? '已挂载' : '尚未挂载',
  });
  checks.push({
    id: 'storage',
    label: '浏览器数据存储',
    status: globalThis.SillyTavern?.libs?.localforage ? 'ok' : 'warn',
    detail: globalThis.SillyTavern?.libs?.localforage ? '使用localforage' : '使用localStorage降级',
  });
  const settings = context ? getSettings() : null;
  checks.push({
    id: 'audit',
    label: '规则审核配置',
    status: settings?.auditEnabled && !settings.auditPrompt.trim() ? 'error' : 'ok',
    detail: settings?.auditEnabled ? (settings.auditPrompt.trim() ? '已启用并填写规则' : '已启用但规则为空') : '未启用',
  });
  if (context) {
    const state = await getChatState(currentChatKey());
    checks.push({
      id: 'sync',
      label: '最近世界书同步',
      status: state.lastSyncStatus === 'failed' ? 'error' : state.lastSyncStatus === 'success' ? 'ok' : 'warn',
      detail: state.lastSyncError || state.lastSyncAt || '尚未同步',
    });
  }
  return checks;
}

export async function diagnosticReport(): Promise<Record<string, any>> {
  const context = tryGetContext();
  const chatKey = context ? currentChatKey() : 'unavailable';
  return {
    version: VERSION,
    timestamp: new Date().toISOString(),
    userAgent: navigator.userAgent,
    location: location.origin,
    chatKey,
    checks: await runDiagnostics(),
    settings: context ? { ...getSettings(), auditPrompt: getSettings().auditPrompt ? '[已填写]' : '' } : null,
    chatState: context ? await getChatState(chatKey) : null,
    taskLog: context ? await getTaskLog(chatKey) : [],
  };
}
