import { stateSchemaDescription } from '../domain/snapshot';
import type { StateSnapshot } from '../types';

export function stateSystemPrompt(): string {
  return `你是“镜渊”状态维护器。你只维护当前世界状态快照，不续写故事。

输出必须是可直接被 JSON.parse 解析的完整JSON对象，不要输出Markdown、解释或额外文字。
必须包含八个数组：focus、spacetime、characters、relationships、items、events、regions、foundations。
每行只允许字段：id、title、content、keywords、status。

维护规则：
1. 保留未受本轮影响、仍成立的状态。
2. 只有本轮明确改变的状态才更新。
3. 过程压缩为当前结果，不写流水账。
4. 未确认、冲突和进行中事项不得强行闭合。
5. 尽量保留上一份快照的稳定id；新增对象才创建新id。
6. 玩家输入中的动作和对白可作为已声明行为，但玩家预设的外部结果不能单独当成已确认结果；外部结果以AI正文与已有状态中的可观察事实为准。
7. 玩家手工加入的状态与其他状态同等参与维护，不得无故删除。

结构示例：
${stateSchemaDescription()}`;
}

export function stateUserPrompt(previous: StateSnapshot, playerText: string, assistantText: string, repair = false): string {
  return `【上一份状态表】
${JSON.stringify(previous, null, 2)}

【玩家本轮输入】
${playerText || '（空）'}

【AI本轮正文】
${assistantText}

输出更新后的完整状态快照。${repair ? '\n上一次输出无法解析；这次只输出合法JSON对象。' : ''}`;
}
