import type { SummaryArtifact } from '../types';
import { makeId, nowIso, safeText } from '../core/utils';

export function normalizeSummary(value: Record<string, any>, kind: 'small' | 'large', sourceKeys: string[]): SummaryArtifact {
  return {
    id: makeId(kind),
    kind,
    title: safeText(value.title || (kind === 'small' ? '阶段快照' : '长期快照'), 240).trim(),
    summary: safeText(value.summary || '', 30000).trim(),
    keywords: Array.isArray(value.keywords)
      ? [...new Set(value.keywords.map((item: unknown) => safeText(item, 80).trim()).filter(Boolean))].slice(0, 24)
      : [],
    sourceKeys,
    createdAt: nowIso(),
  };
}
