export function deepClone<T>(value: T): T {
  if (typeof structuredClone === 'function') {
    try {
      return structuredClone(value);
    } catch {
      // Fall through.
    }
  }
  return JSON.parse(JSON.stringify(value)) as T;
}

export function mergeDefaults<T extends Record<string, any>>(defaults: T, current: Partial<T> | undefined): T {
  const output: Record<string, any> = deepClone(defaults);
  const merge = (target: Record<string, any>, source: Record<string, any> | undefined) => {
    if (!source) return;
    for (const [key, value] of Object.entries(source)) {
      if (value && typeof value === 'object' && !Array.isArray(value) && target[key] && typeof target[key] === 'object' && !Array.isArray(target[key])) {
        merge(target[key], value);
      } else if (value !== undefined) {
        target[key] = value;
      }
    }
  };
  merge(output, current as Record<string, any> | undefined);
  return output as T;
}

export function hashText(value: unknown): string {
  const text = String(value ?? '');
  let hash = 2166136261;
  for (let i = 0; i < text.length; i += 1) {
    hash ^= text.charCodeAt(i);
    hash = Math.imul(hash, 16777619);
  }
  return (hash >>> 0).toString(36);
}

export function makeId(prefix = 'ma'): string {
  if (globalThis.crypto?.randomUUID) return `${prefix}_${globalThis.crypto.randomUUID()}`;
  return `${prefix}_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 10)}`;
}

export function nowIso(): string {
  return new Date().toISOString();
}

export function escapeHtml(value: unknown): string {
  const element = document.createElement('div');
  element.textContent = String(value ?? '');
  return element.innerHTML;
}

export function withTimeout<T>(promise: Promise<T>, ms: number, label: string, controller?: AbortController): Promise<T> {
  return new Promise<T>((resolve, reject) => {
    const timer = window.setTimeout(() => {
      controller?.abort();
      reject(new Error(`${label}超时（${Math.round(ms / 1000)}秒）`));
    }, ms);
    promise.then(
      (value) => {
        window.clearTimeout(timer);
        resolve(value);
      },
      (error) => {
        window.clearTimeout(timer);
        reject(error);
      },
    );
  });
}

export function safeText(value: unknown, max = 100000): string {
  return String(value ?? '').replace(/\u0000/g, '').slice(0, max);
}

export function parseJsonObject(raw: unknown): Record<string, any> {
  const text = safeText(raw).trim();
  if (!text || text === '{}') throw new Error('模型返回为空');
  const fenced = text.match(/```(?:json)?\s*([\s\S]*?)```/i);
  const candidate = (fenced?.[1] ?? text).trim();
  try {
    const parsed = JSON.parse(candidate);
    if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) throw new Error('JSON根节点必须是对象');
    return parsed;
  } catch (error) {
    const start = candidate.indexOf('{');
    const end = candidate.lastIndexOf('}');
    if (start >= 0 && end > start) {
      const parsed = JSON.parse(candidate.slice(start, end + 1));
      if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) throw new Error('JSON根节点必须是对象');
      return parsed;
    }
    throw error instanceof Error ? error : new Error('无法解析模型返回的JSON');
  }
}

export function sanitizeBookName(value: unknown): string {
  return String(value ?? '')
    .replace(/[\\/:*?"<>|]/g, '_')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 80);
}

export function toErrorMessage(error: unknown): string {
  if (error instanceof Error) return error.message;
  return String(error ?? '未知错误');
}
