import { DISPLAY_NAME, MODULE_NAME, VERSION } from '../constants';
import { getContext, getSettings, saveSettings, toast, tryGetContext } from '../core/context';
import { clearAllStorage } from '../storage/repository';
import { installPipelineEventHandlers, latestArtifact, processMessage } from '../pipeline/pipeline';
import { installMessagePanelHandlers, renderAllMessagePanels } from '../ui/message-panel';
import { diagnosticReport } from '../ui/diagnostics';
import { mountOptionalTopButton, mountSettingsPanel } from '../ui/settings-panel';
import { openWorkspace, refreshWorkspace } from '../ui/workspace';

let state: 'idle' | 'initializing' | 'ready' | 'error' = 'idle';
let cleanupPipeline: (() => void) | null = null;
let cleanupPanels: (() => void) | null = null;
let cleanupUiEvents: (() => void) | null = null;
let appReadyHandlerInstalled = false;
let lastError: unknown = null;

function exposeApi(): void {
  (globalThis as any).MirrorAbyss = {
    version: VERSION,
    open: (tab = 'overview') => openWorkspace(tab),
    processLatest: async () => {
      const context = getContext();
      const index = [...(context.chat ?? [])].map((_: any, i: number) => i).reverse().find((i: number) => !context.chat[i]?.is_user && String(context.chat[i]?.mes || '').trim());
      if (index === undefined) throw new Error('没有可整理的AI正文');
      return processMessage(index, true);
    },
    diagnostics: diagnosticReport,
    getState: () => ({ state, lastError: lastError instanceof Error ? lastError.message : String(lastError || '') }),
  };
}

function showFatal(error: unknown): void {
  document.querySelector('#ma11-fatal')?.remove();
  const button = document.createElement('button');
  button.id = 'ma11-fatal';
  button.className = 'ma11-fatal';
  button.type = 'button';
  button.textContent = '镜渊启动失败｜查看诊断';
  button.title = error instanceof Error ? error.message : String(error);
  button.addEventListener('click', () => openWorkspace('diagnostics'));
  document.body.appendChild(button);
}

export async function initialize(): Promise<void> {
  if (state === 'ready' || state === 'initializing') return;
  state = 'initializing';
  lastError = null;
  exposeApi();
  try {
    getSettings();
    await mountSettingsPanel();
    mountOptionalTopButton();
    cleanupPipeline ||= installPipelineEventHandlers();
    cleanupPanels ||= installMessagePanelHandlers();
    renderAllMessagePanels();

    const context = getContext();
    if (!cleanupUiEvents) {
      const rerender = () => {
        renderAllMessagePanels();
        refreshWorkspace();
      };
      context.eventSource.on(context.event_types.CHARACTER_MESSAGE_RENDERED, rerender);
      context.eventSource.on(context.event_types.CHAT_CHANGED, rerender);
      context.eventSource.on(context.event_types.MESSAGE_DELETED, rerender);
      cleanupUiEvents = () => {
        context.eventSource.removeListener?.(context.event_types.CHARACTER_MESSAGE_RENDERED, rerender);
        context.eventSource.removeListener?.(context.event_types.CHAT_CHANGED, rerender);
        context.eventSource.removeListener?.(context.event_types.MESSAGE_DELETED, rerender);
      };
    }

    if (typeof context.registerDebugFunction === 'function') {
      context.registerDebugFunction(
        'mirror_abyss_diagnostics',
        'Mirror Abyss Diagnostics',
        'Open the Mirror Abyss diagnostics panel',
        () => openWorkspace('diagnostics'),
      );
    }

    document.querySelector('#ma11-fatal')?.remove();
    state = 'ready';
    toast('success', `已启动 ${VERSION}`);
  } catch (error) {
    state = 'error';
    lastError = error;
    console.error('[MirrorAbyss] initialization failed', error);
    showFatal(error);
  }
}

export function installAppReadyHandler(): void {
  if (appReadyHandlerInstalled) return;
  appReadyHandlerInstalled = true;
  const context = tryGetContext();
  if (!context) {
    window.setTimeout(installAppReadyHandler, 250);
    appReadyHandlerInstalled = false;
    return;
  }
  context.eventSource.on(context.event_types.APP_READY, () => {
    window.setTimeout(() => void initialize(), 0);
  });
  // Some hosted builds activate user extensions after APP_READY has already fired.
  // A guarded fallback keeps startup independent of event replay semantics.
  window.setTimeout(() => void initialize(), 1200);
}

export async function cleanData(): Promise<void> {
  await clearAllStorage();
  const context = tryGetContext();
  if (context?.extensionSettings?.[MODULE_NAME]) delete context.extensionSettings[MODULE_NAME];
  context?.saveSettingsDebounced?.();
}

export function onEnable(): void {
  if (tryGetContext()) void initialize();
}

export function onDisable(): void {
  getSettings().enabled = false;
  saveSettings();
}

export function onActivate(): void {
  exposeApi();
  installAppReadyHandler();
}

export async function onInstall(): Promise<void> {
  exposeApi();
}

export async function onUpdate(): Promise<void> {
  const settings = tryGetContext() ? getSettings() : null;
  if (settings) {
    settings.migration.legacyChecked = false;
    saveSettings();
  }
}

export async function onClean(): Promise<void> {
  await cleanData();
}

export async function onDelete(): Promise<void> {
  cleanupPipeline?.();
  cleanupPanels?.();
  cleanupUiEvents?.();
  cleanupPipeline = null;
  cleanupPanels = null;
  cleanupUiEvents = null;
  state = 'idle';
}
